<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 10);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        scene.add(dirLight);

        // 3. Ground
        const groundGeometry = new THREE.PlaneGeometry(100, 100);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 4. House Construction
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8b4513 }); // Brown roof
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });

        // Walls (Box)
        const wallGeo = new THREE.BoxGeometry(4, 3, 4);
        const walls = new THREE.Mesh(wallGeo, wallMaterial);
        walls.position.y = 1.5;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Door
        const doorGeo = new THREE.BoxGeometry(1, 2, 0.2);
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x5d4037 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1, 2.1);
        houseGroup.add(door);

        // Windows
        const winGeo = new THREE.BoxGeometry(1, 1, 0.1);
        const win1 = new THREE.Mesh(winGeo, windowMaterial);
        win1.position.set(1.2, 2, 0);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(winGeo, windowMaterial);
        win2.position.set(-1.2, 2, 0);
        houseGroup.add(win2);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(3.5, 2, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 4;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(0.5, 1.5, 0.5);
        const chimneyMat = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const chimney = new THREE.Mesh(chimneyGeo, chimneyMat);
        chimney.position.set(1.5, 5, 1.5);
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 5. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
